    return node(index).item; //调用node()方法
}
Node<E> node(int index) {		//这里采用了索引分开搜索的方法，缩小一半的搜寻量
    // assert isElementIndex(index);

    if (index < (size >> 1)) { //如果索引小于size的一半
        Node<E> x = first;
        for (int i = 0; i < index; i++) //for循环
            x = x.next;
