 */
public Vector() {
    this(10);
}

/**
 * 有参构造方法，构造指定列表内的元素
 */
public Vector(Collection<? extends E> c) {
    Object[] a = c.toArray();  //将集合转化为数组
    elementCount = a.length;  //赋值元素数量
    if (c.getClass() == ArrayList.class) {  //如果c的类型是ArrayList，则直接对elementData赋值
        elementData = a;
